-- Ken's Hardened V2 Fix

local b64_0xlI1lII = {}
local char_0xIlllll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlIIIlI=1,#char_0xIlllll do b64_0xlI1lII[char_0xIlllll:sub(i_0xlIIIlI,i_0xlIIIlI)] = i_0xlIIIlI - 1 end

function b64_0xlI1lII.dec_0xI1lllI(d_0x1lI1II)
    d_0x1lI1II = string.gsub(d_0x1lI1II, '[^'..char_0xIlllll..'=]', '')
    local r_0xIl1l11 = {}
    for i_0xlIIIlI=1, #d_0x1lI1II, 4 do
        local c_0xlIlII1 = b64_0xlI1lII[d_0x1lI1II:sub(i_0xlIIIlI,i_0xlIIIlI)] or 0
        local c_0xll11II = b64_0xlI1lII[d_0x1lI1II:sub(i_0xlIIIlI+1,i_0xlIIIlI+1)] or 0
        local c_0xlIll11, c_0xlIIlll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0x1lI1II:sub(i_0xlIIIlI+2,i_0xlIIIlI+2)
        if ch3 == "=" then has3 = false else c_0xlIll11 = b64_0xlI1lII[ch3] or 0 end
        local ch4 = d_0x1lI1II:sub(i_0xlIIIlI+3,i_0xlIIIlI+3)
        if ch4 == "=" then has4 = false else c_0xlIIlll = b64_0xlI1lII[ch4] or 0 end
        local b_0xIlIllI = c_0xlIlII1 * (2^18) + c_0xll11II * (2^12) + c_0xlIll11 * (2^6) + c_0xlIIlll
        local b_0xlllIll = math.floor(b_0xIlIllI / (2^16)) % (2^8)
        local b_0x1l1lI1 = math.floor(b_0xIlIllI / (2^8)) % (2^8)
        local b_0xI1IIl1 = b_0xIlIllI % (2^8)
        table.insert(r_0xIl1l11, string.char(b_0xlllIll))
        if has3 then table.insert(r_0xIl1l11, string.char(b_0x1l1lI1)) end
        if has4 then table.insert(r_0xIl1l11, string.char(b_0xI1IIl1)) end
    end
    return table.concat(r_0xIl1l11)
end


local function bxor_0xl1lIll(a_0xIlII1I,b_0xlIII1I)
    if bit32 then return bit32.bxor(a_0xIlII1I,b_0xlIII1I) end
    local r_0xl11lIl = 0
    for i_0xl1l1ll = 0, 7 do
        local x_0xIIlll1 = a_0xIlII1I % 2
        local y_0xlIlIIl = b_0xlIII1I % 2
        if x_0xIIlll1 ~= y_0xlIlIIl then r_0xl11lIl = r_0xl11lIl + (2^i_0xl1l1ll) end
        a_0xIlII1I = math.floor(a_0xIlII1I / 2)
        b_0xlIII1I = math.floor(b_0xlIII1I / 2)
    end
    return r_0xl11lIl
end


local function bxor_str_0xI1ll1I(s_0xlI1II1, k_0xlIlIIl)
    local r_0xl1IIII = {}
    for i_0xIlI11l=1, #s_0xlI1II1 do
        local b_0x1lII1l = string.byte(s_0xlI1II1, i_0xIlI11l)
        local kb_0xlIllII = string.byte(k_0xlIlIIl, (i_0xIlI11l-1) % #k_0xlIlIIl + 1)
        r_0xl1IIII[i_0xIlI11l] = string.char(bxor_0xl1lIll(b_0x1lII1l, kb_0xlIllII))
    end
    return table.concat(r_0xl1IIII)
end


local function getkeys_0xIIlllI()
    local seed = b64_0xlI1lII.dec_0xI1lllI("M3FrdGt3eFU=")
    local k1_enc = b64_0xlI1lII.dec_0xI1lllI("eT9aRwYVCy0=")
    local k2_enc = b64_0xlI1lII.dec_0xI1lllI("ajAPGSodGgI=")
    return bxor_str_0xI1ll1I(k1_enc, seed), bxor_str_0xI1ll1I(k2_enc, seed)
end


local function cff_0xllIlII(a_0xI111II)
    local st_0xIllII1 = 0
    local res_0xllllll = a_0xI111II
    while true do
        if st_0xIllII1 == 0 then
            res_0xllllll = res_0xllllll + 1
            st_0xIllII1 = 1
        elseif st_0xIllII1 == 1 then
            res_0xllllll = res_0xllllll * 2
            st_0xIllII1 = 2
        elseif st_0xIllII1 == 2 then
            res_0xllllll = res_0xllllll - 3
            st_0xIllII1 = 3
        else
            break
        end
    end
    return res_0xllllll
end


local function chain_0xl111ll(x) return x*2 end
local function chain_0xlIIIlI(x) return chain_0xl111ll(x)+1 end


local d_0xIII11l = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIIlII = 1
local stk_0xlllIII = {}
stk_0xlllIII._jmp = nil


local disp_0x1Il11l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIlllI()

local state_0x1II11l = 0
while true do
    if state_0x1II11l == 0 then  -- FETCH
        if pc_0xlIIlII > #d_0xIII11l then break end
        local inst = d_0xIII11l[pc_0xlIIlII]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlI1lII.dec_0xI1lllI(val)
            d = bxor_str_0xI1ll1I(d, k2)
            val = bxor_str_0xI1ll1I(d, k1)
        end
        stk_0xlllIII._jmp = nil
        pc_0xlIIlII = pc_0xlIIlII + 1
        cur_op_0xlllIll = opcode
        cur_val_0xI11llI = val
        state_0x1II11l = 1

    elseif state_0x1II11l == 1 then  -- EXECUTE
        local handler = disp_0x1Il11l[cur_op_0xlllIll]
        if handler then
            handler(stk_0xlllIII, cur_val_0xI11llI)
        end
        if stk_0xlllIII._jmp then
            pc_0xlIIlII = pc_0xlIIlII + stk_0xlllIII._jmp
        end
        state_0x1II11l = 0
    else
